code.perFrame:
zoom = 1;
rot = 0;
dx = 0;
dy = 0;
sx = 1;
sy = 1;
warp = 0.001;
cx = 0.5;
cy = 0.5;
wave_x = pow(sin(time*.3011101),5)*.4+.5;;
wave_y = pow(cos(time*.3),3)*.4+.5;;
wave_r = sin(time*.874)*.5+.5;;
wave_g = sin(time*1.54)*.5+.5;;
wave_b = sin(time*1.1)*.5+.5;;
vol= (bass+treb+mid)*.3;;
vol_cap = (max(min(vol,1),.5)-.5)*2;;
wave_r = wave_r*vol_cap;;
wave_g = wave_g*vol_cap;;
wave_b = wave_b*vol_cap;;
ob_size =1;;
ob_r=wave_r*.0;;
ob_g=wave_g*.0;;
ob_b=wave_b*.0;;
q1=wave_x;;
q2=1-wave_y;;
beat=if(((bass*bass_att) > (2.7)),1,0);;
dm=dm-sign(dm)*bass*beat;;
vang=vang+.3*dm/fps;;
q3 = vang;;
monitor = vang;;
//mv_a = 1; decay = 0.81;

code.perVertex:
//cen_x = cos(time)*.2+.3;;
//cen_y = sin(time)*.5+.5;;
cen_x = q1;;
cen_y = q2;;
radxy = sin(time*.1)*.15+.3;;
dist_x = (x-cen_x)/(radxy*(sin(time*.2*0)*.3+cos((cen_x-x+ (cen_y-y))*10+time*2)*.3+1));;
dist_y = (y-cen_y)/(radxy*(sin(time*.2*0)*.3+sin((cen_x-x+ (cen_y-y))*10+time*2)*.3+1));;
in = ((abs(dist_x)) < (1))*((abs(dist_y)) < (1));;
//in = bnot(in);;
out = bnot(in);;
inx =(cen_x-q1)+.08*sign(dist_x)*sqr(1-abs(dist_x));;
iny =(cen_y-q2)+.08*sign(dist_y)*sqr(1-abs(dist_y));;
//**********outside;
vang=q3; //time*.1;;
vx = (x-.5)*cos(vang) - (y-.5)*sin(vang)+.5;;
vy = (x-.5)*sin(vang) +(y-.5)*cos(vang)+.5;;
dvx=.01*sin(time+vy*60*radxy);;
dvy=.01*cos(time+vx*60*radxy);;
outx = dvx*cos(vang) - dvy*sin(vang);;
outy = -dvx*sin(vang) - dvy*cos(vang);;
dx=in*inx+out*outx;;
dy=in*iny+out*outy;
